INSERT INTO background_equipment_options (background_id, option_key, label, gp_amount, notes)
SELECT b.id, data.option_key, data.label, data.gp_amount, data.notes
FROM _import_background_equipment_option_data data
JOIN backgrounds b ON b.name = data.background_name
ON CONFLICT (background_id, option_key) DO UPDATE SET
    label = EXCLUDED.label,
    gp_amount = EXCLUDED.gp_amount,
    notes = EXCLUDED.notes;

