DELETE FROM background_equipment_items bei
USING background_equipment_options beo, backgrounds b, _import_background_equipment_option_data data
WHERE bei.equipment_option_id = beo.id
  AND beo.background_id = b.id
  AND b.name = data.background_name;

INSERT INTO background_equipment_items (
    equipment_option_id, item_id, item_name, quantity, notes
)
SELECT
    beo.id,
    i.id,
    data.item_name,
    data.quantity,
    data.notes
FROM _import_background_equipment_item_data data
JOIN backgrounds b ON b.name = data.background_name
JOIN background_equipment_options beo
    ON beo.background_id = b.id
   AND beo.option_key = data.option_key
LEFT JOIN items i ON i.name = data.lookup_name;

COMMIT;
